#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int mat[n][m];
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                scanf("%d", &mat[i][j]);
            }
        }
        int first = 1;
        for (int i = 0; i < n; ++i) {
            if (i % 2 == 0) {
                for (int j = 0; j < m; ++j) {
                    if (!first) printf(" ");
                    printf("%d", mat[i][j]);
                    first = 0;
                }
            } else {
                for (int j = m - 1; j >= 0; --j) {
                    if (!first) printf(" ");
                    printf("%d", mat[i][j]);
                    first = 0;
                }
            }
        }
        if (T) printf("\n");
    }
    return 0;
}

