#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    outputs = []
    for _ in range(T):
        n = int(next(it))
        m = int(next(it))
        # read matrix row by row
        mat = [[int(next(it)) for _ in range(m)] for __ in range(n)]
        res = []
        for i in range(n):
            if i % 2 == 0:
                res.extend(mat[i])
            else:
                res.extend(reversed(mat[i]))
        outputs.append(' '.join(map(str, res)))
    sys.stdout.write('\n'.join(outputs))

if __name__ == "__main__":
    main()

