const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = Number(input[idx++]);
let outLines = [];
for (let tc = 0; tc < T; ++tc) {
  const n = Number(input[idx++]);
  const m = Number(input[idx++]);
  const mat = [];
  for (let i = 0; i < n; ++i) {
    const row = [];
    for (let j = 0; j < m; ++j) row.push(Number(input[idx++]));
    mat.push(row);
  }
  const res = [];
  for (let i = 0; i < n; ++i) {
    if (i % 2 === 0) {
      for (let j = 0; j < m; ++j) res.push(mat[i][j]);
    } else {
      for (let j = m - 1; j >= 0; --j) res.push(mat[i][j]);
    }
  }
  outLines.push(res.join(' '));
}
process.stdout.write(outLines.join('\n'));
